import { GoogleGenAI, Type } from "@google/genai";
import { Industry } from "./types";

export const generateIndustryDraft = async (pkd: string, name: string): Promise<Partial<Industry>> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Przygotuj profesjonalną analizę branży o kodzie PKD ${pkd} (${name}) dla doradcy bankowego w Polsce. 
               Zwróć uwagę na specyfikę lokalnego rynku.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          description: { type: Type.STRING },
          businessModel: { type: Type.STRING },
          costDrivers: { type: Type.ARRAY, items: { type: Type.STRING } },
          revenueDrivers: { type: Type.ARRAY, items: { type: Type.STRING } },
          keyKPIs: { 
            type: Type.ARRAY, 
            items: { 
              type: Type.OBJECT, 
              properties: { 
                label: { type: Type.STRING }, 
                value: { type: Type.STRING } 
              } 
            } 
          },
          funFacts: { type: Type.ARRAY, items: { type: Type.STRING } },
          checklistQuestions: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ["description", "businessModel", "costDrivers", "revenueDrivers", "keyKPIs", "funFacts", "checklistQuestions"]
      }
    }
  });

  try {
    const data = JSON.parse(response.text);
    return {
      description: data.description,
      businessModel: data.businessModel,
      costDrivers: data.costDrivers,
      revenueDrivers: data.revenueDrivers,
      keyKPIs: data.keyKPIs,
      funFacts: data.funFacts,
      checklist: data.checklistQuestions.map((q: string, idx: number) => ({
        id: `gen-${idx}`,
        question: q,
        isDone: false
      }))
    };
  } catch (e) {
    console.error("Failed to parse AI response", e);
    throw e;
  }
};

import React, { useState, useEffect } from 'react';
import { Industry, AppView } from './types';
import { INITIAL_INDUSTRIES } from './constants';
import AdvisorView from './components/AdvisorView';
import AdminView from './components/AdminView';
import Layout from './components/Layout';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>('ADVISOR');
  const [industries, setIndustries] = useState<Industry[]>([]);

  // Load data from local storage or use initial data
  useEffect(() => {
    const saved = localStorage.getItem('bnp_industries');
    if (saved) {
      setIndustries(JSON.parse(saved));
    } else {
      setIndustries(INITIAL_INDUSTRIES);
      localStorage.setItem('bnp_industries', JSON.stringify(INITIAL_INDUSTRIES));
    }
  }, []);

  const handleUpdateIndustries = (updated: Industry[]) => {
    setIndustries(updated);
    localStorage.setItem('bnp_industries', JSON.stringify(updated));
  };

  return (
    <Layout currentView={view} setView={setView}>
      {view === 'ADVISOR' ? (
        <AdvisorView industries={industries} />
      ) : (
        <AdminView industries={industries} setIndustries={handleUpdateIndustries} />
      )}
    </Layout>
  );
};

export default App;

