import React, { useState } from 'react';

interface AdminLoginModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSuccess: () => void;
}

const AdminLoginModal: React.FC<AdminLoginModalProps> = ({ isOpen, onClose, onSuccess }) => {
  const [pin, setPin] = useState('');
  const [error, setError] = useState(false);

  const correctPin = '2025'; // Domyślny kod dostępu

  if (!isOpen) return null;

  const handleDigit = (digit: string) => {
    if (pin.length < 4) {
      const newPin = pin + digit;
      setPin(newPin);
      setError(false);

      if (newPin.length === 4) {
        if (newPin === correctPin) {
          onSuccess();
          setPin('');
        } else {
          setError(true);
          setTimeout(() => setPin(''), 500);
        }
      }
    }
  };

  const handleClear = () => setPin('');

  return (
    <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-xs overflow-hidden animate-scaleIn">
        <div className="p-6 text-center">
          <div className="bg-emerald-50 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4">
            <svg className="w-8 h-8 text-[#00915a]" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
            </svg>
          </div>
          <h3 className="text-xl font-bold text-gray-900 mb-1">Dostęp administracyjny</h3>
          <p className="text-sm text-gray-500 mb-6">Wprowadź 4-cyfrowy kod PIN</p>

          <div className="flex justify-center space-x-3 mb-8">
            {[...Array(4)].map((_, i) => (
              <div 
                key={i} 
                className={`w-4 h-4 rounded-full border-2 transition-all duration-200 ${
                  pin.length > i 
                    ? 'bg-[#00915a] border-[#00915a] scale-110' 
                    : error 
                      ? 'border-red-500 bg-red-100 animate-shake' 
                      : 'border-gray-200'
                }`}
              ></div>
            ))}
          </div>

          <div className="grid grid-cols-3 gap-3">
            {['1', '2', '3', '4', '5', '6', '7', '8', '9'].map(d => (
              <button
                key={d}
                onClick={() => handleDigit(d)}
                className="h-14 rounded-2xl bg-gray-50 text-xl font-bold text-gray-700 hover:bg-emerald-50 hover:text-[#00915a] transition-colors active:scale-95"
              >
                {d}
              </button>
            ))}
            <button onClick={onClose} className="h-14 rounded-2xl text-xs font-bold text-gray-400 uppercase">Anuluj</button>
            <button
              onClick={() => handleDigit('0')}
              className="h-14 rounded-2xl bg-gray-50 text-xl font-bold text-gray-700 hover:bg-emerald-50 hover:text-[#00915a] transition-colors active:scale-95"
            >
              0
            </button>
            <button onClick={handleClear} className="h-14 rounded-2xl text-xs font-bold text-gray-400 uppercase">Kasuj</button>
          </div>
        </div>
      </div>
    </div>
  );
};

